1161     llvm::computeKnownBits(I->getOperand(0), LHSKnown, Depth + 1, Q);
1162     Known = analyzeKnownBitsFromAndXorOr(cast<Operator>(I), LHSKnown, RHSKnown,
1163                                          Depth, Q);
