410 // Attribute compatiblity rules are generated to check the attribute of the
411 // caller and callee and decide whether inlining should be allowed. CompatRule
412 // and child classes are used for the rule generation. CompatRule takes only a
413 // compare function which could be templated with the attribute type.
414 // CompatRuleStrAttr takes the compare function and the string attribute for
415 // checking compatibility for inline substitution.
416 class CompatRule<string F> {
417   // The function's signature must match "bool(const Function&, const
418   // Function&)", where the first parameter is the reference to the caller and
419   // the second parameter is the reference to the callee. It must return false
420   // if the attributes of the caller and callee are incompatible, and true
421   // otherwise.
422   string CompatFunc = F;
423   string AttrName = "";
424 }
425 
426 class CompatRuleStrAttr<string F, string Attr> : CompatRule<F> {
427   // The checker function is extended with an third argument as the function
428   // attribute string "bool(const Function&, const Function&, const StringRef&)".
429   string AttrName = Attr;
430 }
